PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?lakeLabel WHERE {
  {
    SELECT ?city ?population WHERE {
      ?city wdt:P17 wd:Q16 .
      ?city wdt:P31/wdt:P279* wd:Q515 .
      ?city wdt:P206 ?lake .
      ?lake wdt:P31/wdt:P279* wd:Q39715 .
      ?city p:P1082 ?statement .
      ?statement ps:P1082 ?population ;
                 pq:P585 ?time .
      {
        SELECT ?city (MAX(?time) AS ?maxTime) WHERE {
          ?city p:P1082 ?stmt .
          ?stmt pq:P585 ?time .
          FILTER (datatype(?time) = xsd:dateTime)
        }
        GROUP BY ?city
      }
      FILTER (?time = ?maxTime)
    }
    ORDER BY ?population
    LIMIT 1
  }
  ?lake rdfs:label ?lakeLabel .
  FILTER (lang(?lakeLabel) = "en")
}

